def min_leftover_chars(s, k):
    """
    Given a string s and an integer k, split the string into at most k substrings such that
    each character in the string appears in at most one substring. Return the minimum number
    of leftover characters that cannot be included in any of the k substrings.

    :param s: The input string
    :param k: The maximum number of substrings to split the string into
    :return: The minimum number of leftover characters
    """
    if k >= len(s):
        return 0

    from collections import Counter
    char_count = Counter(s)
    max_chars_per_substring = len(s) // k + (1 if len(s) % k > 0 else 0)

    def can_split(max_chars):
        used_chars = set()
        for char, count in char_count.items():
            if count > max_chars:
                used_chars.add(char)
            elif count <= max_chars:
                if len(used_chars) < k:
                    used_chars.add(char)
                else:
                    return False
        return True

    left, right = 0, max_chars_per_substring
    while left < right:
        mid = (left + right + 1) // 2
        if can_split(mid):
            left = mid
        else:
            right = mid - 1

    return sum(count > left for count in char_count.values())
