def min_leftover_chars(s, word_dict):
    def dfs(index, path_length):
        if index == len(s):
            return path_length
        min_leftover = float('inf')
        for word in word_dict:
            if s.startswith(word, index):
                leftover = dfs(index + len(word), path_length + 1)
                min_leftover = min(min_leftover, leftover)
        return min_leftover

    result = dfs(0, 0)
    return len(s) - result if result != float('inf') else -1

