        for i in range(1, len(subarr)):
            if (subarr[i] % 2 == subarr[i - 1] % 2) or subarr[i] > threshold:
                return False
        return True

    max_len = 0
    for start in range(len(nums)):
        if nums[start] % 2 == 0 and nums[start] <= threshold:
            end = start + 1
            while end < len(nums) and nums[end] <= threshold:
                if nums[end] % 2 != nums[end - 1] % 2:
                    end += 1
                else:
                    break
            if is_alternating(nums[start:end]):
                max_len = max(max_len, end - start)

    return max_len

