def max_non_decreasing_subarray(nums1, nums2):
    n = len(nums1)
    dp = [[0, 0] for _ in range(n)]  # dp[i][0]: length ending at i from nums1, dp[i][1]: length ending at i from nums2

    # Initialize the first element
    if nums1[0] <= nums1[0]:
        dp[0][0] = 1
    if nums2[0] <= nums2[0]:
        dp[0][1] = 1

    max_length = 1  # At least one element is a valid subarray

    for i in range(1, n):
        # Pick from nums1
        if nums1[i] >= nums1[i-1]:
            dp[i][0] = dp[i-1][0] + 1
        else:
            dp[i][0] = 1

        # Pick from nums2
        if nums2[i] >= nums2[i-1]:
            dp[i][1] = dp[i-1][1] + 1
        else:
            dp[i][1] = 1

        # Merge the results
        max_length = max(max_length, dp[i][0], dp[i][1])

    return max_length
